import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";
import DropshippingExpandedContent, { DROPSHIPPING_EXPANDED_FAQS } from "@/components/DropshippingExpandedContent";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

function fmt(n: number) {
  return formatCurrencyValue(n, { maximumFractionDigits: 2 });
}

const PLANS = [
  { name: "Basic", rate: 0.029, fixed: 0.30, monthly: 39 },
  { name: "Shopify", rate: 0.026, fixed: 0.30, monthly: 105 },
  { name: "Advanced", rate: 0.024, fixed: 0.30, monthly: 399 },
];

const EXPANDED_FAQS = DROPSHIPPING_EXPANDED_FAQS.shopify;


const FAQS = [
  { q: "What are Shopify's transaction fees?", a: "Shopify Payments charges: Basic 2.9% + $0.30, Shopify plan 2.6% + $0.30, Advanced plan 2.4% + $0.30. These apply per online credit card transaction using Shopify Payments." },
  { q: "Does Shopify charge extra if I use a third-party payment provider?", a: "Yes. If you use a payment provider other than Shopify Payments, Shopify adds an additional fee: 2% (Basic), 1% (Shopify), or 0.5% (Advanced) per transaction." },
  { q: "Are there transaction fees on Shopify Starter?", a: "The Shopify Starter plan charges 5% per transaction. It's best for low-volume sellers or those just starting out - upgrade to Basic or Shopify plan once sales volume grows." },
  { q: "How can I minimize my Shopify fees?", a: "Use Shopify Payments to avoid the additional third-party fee, upgrade to a higher plan if volume justifies lower per-transaction rates, and bundle higher-value products to reduce fixed fee impact." },
  { q: "When does it make sense to upgrade from Basic to Shopify plan?", a: "Upgrade when the fee savings exceed the plan cost difference. From Basic ($39) to Shopify ($105): cost difference = $66/month. Fee savings = 0.3% per transaction. At $66 savings  x  0.3% = $22,000/month in revenue, the upgrade pays for itself." },
  { q: "Are Shopify subscription fees tax-deductible?", a: "Yes. Shopify monthly plan fees and transaction fees are business expenses and are tax-deductible in most jurisdictions. Keep records of all Shopify charges for tax reporting." },
  { q: "What is Shopify's fee for international credit cards?", a: "International credit cards may incur an additional 1.5% currency conversion fee when the customer's card currency differs from your store's default currency, on top of the standard processing rate." },
  { q: "How does Shopify's $0.30 fixed fee affect small vs. large orders?", a: "The $0.30 fixed fee has more impact on small orders. On a $5 order, $0.30 = 6% of the transaction. On a $100 order, $0.30 = 0.3%. High-volume stores with low average order values feel this most acutely." },
];

export default function ShopifyFeeCalculator() {
  useCurrencyVersion();
  const [price, setPrice] = useState(50);
  const [units, setUnits] = useState(100);

  const totalRevenue = price * units;

  return (
    <>
      <SEOHead
        title="Free Shopify Fee Calculator Online - Compare All Plan Fees Instantly | CalcHive"
        description="Free online Shopify fee calculator. Compare transaction fees across Shopify Basic, Shopify and Advanced plans instantly. 100% free, no account needed, works for all Shopify sellers."
        canonical="/shopify-fee-calculator"
        keywords="free shopify fee calculator, shopify transaction fee calculator free, shopify plan fee comparison free, shopify fee calculator online free, shopify seller fee calculator"
        category="Dropshipping"
        faqs={EXPANDED_FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="inline-flex items-center gap-1.5 text-xs font-semibold uppercase tracking-widest text-emerald-600 dark:text-emerald-400 bg-emerald-50 dark:bg-emerald-950/50 px-3 py-1 rounded-full mb-4">Dropshipping</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Shopify Fee Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free Shopify fee calculator to compare Shopify transaction fee calculator free results across Basic, Shopify, and Advanced plans side-by-side. Enter your product price and monthly sales volume to see which plan delivers the highest net revenue at your specific volume. This Shopify plan fee comparison free tool also works as a Shopify fee calculator online free and a Shopify seller fee calculator.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            <SliderInput id="product-price-s" label="Product Price" value={price} min={1} max={1000} step={1} onChange={setPrice} format={fmt} testId="input-product-price" />
            <SliderInput id="monthly-units" label="Monthly Sales (units)" value={units} min={1} max={10000} step={10} onChange={setUnits} testId="input-monthly-units" helpText="orders/month" />
          </div>
          <motion.div key={`${price}-${units}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-4">
              {PLANS.map((plan, i) => {
                const perTxFee = price * plan.rate + plan.fixed;
                const totalFees = perTxFee * units + plan.monthly;
                const netRevenue = totalRevenue - totalFees;
                const effectiveRate = totalRevenue > 0 ? (totalFees / totalRevenue * 100).toFixed(2) : "0";
                const isHighlighted = i === 1;
                return (
                  <div key={plan.name} className={`rounded-2xl p-5 border transition-shadow hover:shadow-md ${isHighlighted ? "bg-gradient-to-br from-emerald-500 to-emerald-700 border-emerald-600 text-white" : "bg-accent/60 border-border"}`}>
                    <p className={`text-xs font-bold uppercase tracking-wide mb-1 ${isHighlighted ? "text-white/70" : "text-primary"}`}>{plan.name}</p>
                    <p className={`text-xs mb-3 ${isHighlighted ? "text-white/60" : "text-muted-foreground"}`}>{(plan.rate * 100).toFixed(1)}% + $0.30 - ${plan.monthly}/mo</p>
                    <p className={`text-xs ${isHighlighted ? "text-white/70" : "text-muted-foreground"}`}>Net Revenue</p>
                    <p className={`text-2xl font-extrabold mb-1 ${isHighlighted ? "text-white" : "text-foreground"}`} data-testid={`result-net-${plan.name.toLowerCase()}`}>{fmt(netRevenue)}</p>
                    <p className={`text-xs ${isHighlighted ? "text-white/60" : "text-muted-foreground"}`}>Total fees: {fmt(totalFees)} ({effectiveRate}%)</p>
                  </div>
                );
              })}
            </div>
            <div className="bg-accent/40 border border-border rounded-xl p-4 text-sm text-muted-foreground">
              Gross revenue: <strong className="text-foreground">{fmt(totalRevenue)}/month</strong> ({units} orders  x  {fmt(price)})
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How Much Does Shopify Charge Per Transaction</h2>
          <p className="text-muted-foreground leading-relaxed">Shopify charges two types of fees: a percentage-based transaction fee and a fixed $0.30 per transaction (for online orders), plus a flat monthly subscription fee. The effective rate depends on both your average order value and total monthly volume.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Per Transaction Fee = (Order Price  x  Rate%) + $0.30</p>
            <p>Monthly Fees = (Per Transaction Fee  x  Orders) + Monthly Plan Fee</p>
            <p>Net Revenue = Gross Revenue - Monthly Fees</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Compare Shopify Basic vs Shopify vs Advanced Fees for Free</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Plan Upgrade", "Monthly Cost Increase", "Transaction Fee Savings", "Break-Even Monthly Revenue"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["Basic to Shopify", "$66/mo ($105 - $39)", "0.3% per transaction", `${fmt(66 / 0.003)}/month`],
                  ["Shopify to Advanced", "$294/mo ($399 - $105)", "0.2% per transaction", `${fmt(294 / 0.002)}/month`],
                ].map(([upgrade, cost, savings, breakeven]) => (
                  <tr key={upgrade} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{upgrade}</td>
                    <td className="py-2.5 px-4 text-red-600 dark:text-red-400">{cost}</td>
                    <td className="py-2.5 px-4 text-emerald-600 dark:text-emerald-400 font-medium">{savings}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{breakeven}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Fee Calculator for Every Shopify Store Owner</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Feature", "Basic ($39/mo)", "Shopify ($105/mo)", "Advanced ($399/mo)"].map(h => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["Online Credit Card Rate", "2.9% + $0.30", "2.6% + $0.30", "2.4% + $0.30"],
                  ["In-Person Card Rate", "2.7%", "2.5%", "2.4%"],
                  ["3rd-Party Payment Fee", "2.0%", "1.0%", "0.5%"],
                  ["Staff Accounts", "2 staff", "5 staff", "15 staff"],
                  ["Shipping Discount", "Up to 77%", "Up to 88%", "Up to 88%"],
                  ["Advanced Reporting", "No", "No", "Yes"],
                  ["Calculated Shipping", "No", "No", "Yes"],
                  ["Best For", "Starting out", "Growing stores", "High-volume stores"],
                ].map(([feature, basic, shopify, advanced]) => (
                  <tr key={feature} className="hover:bg-muted/30">
                    <td className="py-2.5 px-3 font-semibold text-foreground">{feature}</td>
                    <td className="py-2.5 px-3 text-muted-foreground">{basic}</td>
                    <td className="py-2.5 px-3 text-muted-foreground">{shopify}</td>
                    <td className="py-2.5 px-3 text-muted-foreground">{advanced}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <DropshippingExpandedContent kind="shopify" />

        <section className="mb-8">
          <h2 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h2>
          <div className="space-y-3">{EXPANDED_FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/shopify-fee-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


